import json
from datetime import datetime, timezone
from typing import List

import modal
from fastapi import FastAPI

app = modal.App("modal-event-pipeline")

image = modal.Image.debian_slim().pip_install("fastapi")

queue = modal.Queue.from_name("modal-event-pipeline-queue", create_if_missing=True)
volume = modal.Volume.from_name("modal-event-pipeline-vol", create_if_missing=True)
status_dict = modal.Dict.from_name("modal-event-pipeline-output", create_if_missing=True)

OUTPUT_PATH = "/events/processed_events.json"


def _now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


@app.function(image=image)
def produce_events() -> List[dict]:
    events = []
    for i in range(10):
        event = {
            "event_id": i,
            "timestamp": _now_iso(),
            "payload": f"synthetic event payload {i}",
        }
        events.append(event)
        queue.put(event)
    return events


@app.function(image=image, volumes={"/events": volume})
def consume_events() -> List[dict]:
    processed_events = []
    while True:
        event = queue.get(timeout=1)
        if event is None:
            break
        payload_words = str(event.get("payload", "")).split()
        processed_event = {
            **event,
            "processed": True,
            "word_count": len(payload_words),
        }
        processed_events.append(processed_event)

    with open(OUTPUT_PATH, "w", encoding="utf-8") as handle:
        json.dump(processed_events, handle, indent=2)

    volume.commit()
    return processed_events


fastapi_app = FastAPI()


@fastapi_app.get("/")
async def read_status() -> dict:
    return {
        "events_produced": await status_dict.get("events_produced"),
        "events_consumed": await status_dict.get("events_consumed"),
        "processing_complete": await status_dict.get("processing_complete"),
        "output_path": await status_dict.get("output_path"),
    }


@app.function(image=image)
@modal.asgi_app()
def status_endpoint():
    return fastapi_app


@app.local_entrypoint()
def main():
    produced = produce_events.remote()
    consumed = consume_events.remote()

    status_dict["events_produced"] = len(produced)
    status_dict["events_consumed"] = len(consumed)
    status_dict["processing_complete"] = "true"
    status_dict["output_path"] = OUTPUT_PATH

